const express = require('express');
const router = express.Router();
const { AllianceController, generateInviteLink, joinByInviteLink, getInviteLinks, deleteInviteLink } = require('../controllers/allianceController');
const { authenticateToken } = require('../middleware/auth');

// 所有路由都需要认证
router.use(authenticateToken);

// 创建联盟
router.post('/', AllianceController.createAlliance);

// 搜索联盟
router.get('/search', AllianceController.searchAlliances);

// 获取用户所属联盟（必须在 /:id 之前）
router.get('/user/alliance', AllianceController.getUserAlliance);

// 获取用户联盟颜色
router.get('/user/color', AllianceController.getUserAllianceColor);

// 获取用户联盟旗帜信息
router.get('/user/flag', authenticateToken, AllianceController.getUserAllianceFlag);

// 获取可用的联盟旗帜图案
router.get('/flag-patterns', AllianceController.getAvailableFlagPatterns);

// 获取联盟详情
router.get('/:id', AllianceController.getAllianceDetails);

// 获取联盟成员列表
router.get('/:id/members', AllianceController.getAllianceMembers);

// 获取联盟统计数据
router.get('/:id/stats', AllianceController.getAllianceStats);

// 踢出联盟成员
router.post('/:id/kick-member', AllianceController.kickMember);

// 更新成员角色
router.post('/:id/update-member-role', AllianceController.updateMemberRole);

// 转让盟主
router.post('/:id/transfer-leadership', AllianceController.transferLeadership);

// 申请加入联盟
router.post('/:id/apply', AllianceController.applyToAlliance);

// 加入联盟（别名，与前端保持一致）
router.post('/:id/join', AllianceController.applyToAlliance);

// 获取联盟申请列表
router.get('/:id/applications', AllianceController.getApplications);

// 审批联盟申请
router.post('/:id/review-application', AllianceController.reviewApplication);

// 退出联盟
router.post('/leave', AllianceController.leaveAlliance);

// 更新联盟信息（仅盟主和管理员）
router.put('/:id', AllianceController.updateAlliance);

// 转让盟主（仅盟主）
router.post('/:id/transfer-leadership', AllianceController.transferLeadership);

// 解散联盟（仅盟主）
router.delete('/:id', AllianceController.disbandAlliance);

// 邀请链接相关路由
// 生成邀请链接
router.post('/:allianceId/invite', generateInviteLink);

// 通过邀请链接加入联盟
router.post('/join-by-invite', joinByInviteLink);

// 获取联盟邀请链接列表
router.get('/:allianceId/invites', getInviteLinks);

// 删除邀请链接
router.delete('/:allianceId/invites/:inviteId', deleteInviteLink);

module.exports = router;
